import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
} from 'react-native';
import ReactNativeBiometrics from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_KEY = '@user_authenticated';
const PASSWORD_KEY = '@user_password';

const rnBiometrics = new ReactNativeBiometrics();

const BiometricAuthScreen = ({ navigation }) => {
  const [loading, setLoading] = useState(true);
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState('');
  const [password, setPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);

  useEffect(() => {
    checkAuthenticationStatus();
  }, []);

  const checkAuthenticationStatus = async () => {
    try {
      const isAuthenticated = await AsyncStorage.getItem(AUTH_KEY);
      
      if (isAuthenticated === 'true') {
        navigation.replace('Home');
        return;
      }

      await checkBiometricAvailability();
    } catch (error) {
      console.error('Error checking authentication status:', error);
      setLoading(false);
    }
  };

  const checkBiometricAvailability = async () => {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      
      setBiometricsAvailable(available);
      setBiometricType(biometryType);
      
      if (available) {
        setTimeout(() => {
          authenticateWithBiometrics();
        }, 500);
      } else {
        setShowPasswordInput(true);
      }
      
      setLoading(false);
    } catch (error) {
      console.error('Error checking biometric availability:', error);
      setShowPasswordInput(true);
      setLoading(false);
    }
  };

  const authenticateWithBiometrics = async () => {
    try {
      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: 'Authenticate to continue',
        cancelButtonText: 'Use Password',
      });

      if (success) {
        await handleSuccessfulAuthentication();
      } else {
        setShowPasswordInput(true);
      }
    } catch (error) {
      console.error('Biometric authentication error:', error);
      Alert.alert(
        'Authentication Failed',
        'Biometric authentication failed. Please use password.',
        [{ text: 'OK', onPress: () => setShowPasswordInput(true) }]
      );
    }
  };

  const authenticateWithPassword = async () => {
    if (!password.trim()) {
      Alert.alert('Error', 'Please enter your password');
      return;
    }

    try {
      const storedPassword = await AsyncStorage.getItem(PASSWORD_KEY);
      
      if (!storedPassword) {
        await AsyncStorage.setItem(PASSWORD_KEY, password);
        await handleSuccessfulAuthentication();
      } else {
        if (password === storedPassword) {
          await handleSuccessfulAuthentication();
        } else {
          Alert.alert('Error', 'Incorrect password');
          setPassword('');
        }
      }
    } catch (error) {
      console.error('Password authentication error:', error);
      Alert.alert('Error', 'Authentication failed. Please try again.');
    }
  };

  const handleSuccessfulAuthentication = async () => {
    try {
      await AsyncStorage.setItem(AUTH_KEY, 'true');
      navigation.replace('Home');
    } catch (error) {
      console.error('Error storing authentication status:', error);
      Alert.alert('Error', 'Failed to save authentication status');
    }
  };

  const retryBiometricAuth = () => {
    setShowPasswordInput(false);
    authenticateWithBiometrics();
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Authentication Required</Text>
      
      {biometricsAvailable && !showPasswordInput && (
        <View style={styles.biometricContainer}>
          <Text style={styles.biometricText}>
            Authenticate using {biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}
          </Text>
          <TouchableOpacity
            style={styles.biometricButton}
            onPress={authenticateWithBiometrics}
          >
            <Text style={styles.buttonText}>
              Use {biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}
            </Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={styles.fallbackButton}
            onPress={() => setShowPasswordInput(true)}
          >
            <Text style={styles.fallbackText}>Use Password Instead</Text>
          </TouchableOpacity>
        </View>
      )}

      {showPasswordInput && (
        <View style={styles.passwordContainer}>
          <Text style={styles.passwordLabel}>Enter Password</Text>
          <TextInput
            style={styles.input}
            placeholder="Password"
            secureTextEntry
            value={password}
            onChangeText={setPassword}
            autoFocus
          />
          <TouchableOpacity
            style={styles.loginButton}
            onPress={authenticateWithPassword}
          >
            <Text style={styles.buttonText}>Login</Text>
          </TouchableOpacity>
          
          {biometricsAvailable && (
            <TouchableOpacity
              style={styles.fallbackButton}
              onPress={retryBiometricAuth}
            >
              <Text style={styles.fallbackText}>
                Use {biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}
              </Text>
            </TouchableOpacity>
          )}
        </View>
      )}

      {!biometricsAvailable && !showPasswordInput && (
        <View style={styles.noBiometricsContainer}>
          <Text style={styles.noBiometricsText}>
            Biometric authentication is not available on this device
          </Text>
          <TouchableOpacity
            style={styles.loginButton}
            onPress={() => setShowPasswordInput(true)}
          >
            <Text style={styles.buttonText}>Continue with Password</Text>
          </TouchableOpacity>
        </View>
      )}
    </View>
  );
};

const HomeScreen = ({ navigation }) => {
  const handleLogout = async () => {
    try {
      await AsyncStorage.removeItem(AUTH_KEY);
      navigation.replace('Auth');
    } catch (error) {
      console.error('Logout error:', error);
      Alert.alert('Error', 'Failed to logout');
    }
  };

  const handleResetPassword = async () => {
    Alert.alert(
      'Reset Password',
      'Are you sure you want to reset your password?',
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Reset',
          style: 'destructive',
          onPress: async () => {
            try {
              await AsyncStorage.removeItem(PASSWORD_KEY);
              await AsyncStorage.removeItem(AUTH_KEY);
              Alert.alert('Success', 'Password reset. Please login again.');
              navigation.replace('Auth');
            } catch (error) {
              console.error('Reset error:', error);
              Alert.alert('Error', 'Failed to reset password');
            }
          },
        },
      ]
    );
  };

  return (
    <View style={styles.container}>
      <Text style={styles.homeTitle}>Welcome!</Text>
      <Text style={styles.homeText}>You have successfully authenticated</Text>
      
      <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
      
      <TouchableOpacity style={styles.resetButton} onPress={handleResetPassword}>
        <Text style={styles.resetButtonText}>Reset Password</Text>
      </TouchableOpacity>
    </View>
  );
};

